package com.sloopworks.dayfold.client

import androidx.compose.ui.graphics.Color
import androidx.compose.ui.graphics.SolidColor
import androidx.compose.ui.graphics.vector.ImageVector
import androidx.compose.ui.graphics.vector.addPathNodes
import androidx.compose.ui.unit.dp

// On-brand icons as Compose ImageVectors built from Material Symbols Rounded SVG path
// data (viewBox "0 -960 960 960"; paths live in y∈[-960,0] so a group shifts them up).
// This matches the design's Material Symbols WITHOUT an icon-library dependency (a
// deliberate project choice) or a bundled icon font (~15 MB): just ~1 KB of path data
// per icon, recolored by `Icon(tint=…)`. Replaces emoji, which render off-brand and
// inconsistently across platforms.
private fun ms(path: String): ImageVector =
  ImageVector.Builder(defaultWidth = 24.dp, defaultHeight = 24.dp, viewportWidth = 960f, viewportHeight = 960f)
    .apply {
      addGroup(translationY = 960f)
      addPath(pathData = addPathNodes(path), fill = SolidColor(Color.Black))
      clearGroup()
    }.build()

